11	import * as React from 'react';
12	import { useTranslation } from 'react-i18next';
13	import { Record } from '../../api/ipfix';
14	import { NetflowMetrics, Stats } from '../../api/loki';
15	import { RecordType } from '../../model/flow-query';
16	import { Warning } from '../../model/warnings';
17	import { TimeRange } from '../../utils/datetime';
18	import { defaultSize, maxSize, minSize } from '../../utils/panel';
19	import { SummaryPanelContent } from './summary-panel-content';
20	import './summary-panel.css';
21	
22	export interface SummaryPanelProps {
23	  onClose: () => void;
24	  flows?: Record[];
25	  metrics: NetflowMetrics;
26	  type: RecordType;
27	  stats?: Stats;
28	  maxChunkAge?: number;
29	  limit: number;
30	  range: number | TimeRange;
31	  lastRefresh?: Date;
32	  lastDuration?: number;
33	  warning?: Warning;
34	  showDNSLatency?: boolean;
35	  showRTTLatency?: boolean;
36	  id?: string;
37	}
38	
39	export const SummaryPanel: React.FC<SummaryPanelProps> = ({
40	  flows,
41	  metrics,
42	  type,
43	  maxChunkAge,
44	  stats,
45	  limit,
46	  range,
47	  lastRefresh,
48	  lastDuration,
49	  warning,
50	  showDNSLatency,
51	  showRTTLatency,
52	  id,
53	  onClose
54	}) => {
55	  const { t } = useTranslation('plugin__netobserv-plugin');
56	
57	  return (
58	    <DrawerPanelContent
59	      data-test-id={id}
60	      id={id}
61	      className="drawer-panel-content"
62	      isResizable
63	      defaultSize={defaultSize}
64	      minSize={minSize}
65	      maxSize={maxSize}
66	    >
67	      <DrawerHead id={`${id}-drawer-head`} data-test-id="drawer-head" className="drawer-head">
68	        <Text data-test-id="drawer-head-text" component={TextVariants.h2}>
69	          {t('Query summary')}
70	        </Text>
71	        <DrawerActions>
72	          <DrawerCloseButton id={`${id ? id : 'summary-panel'}-close-button`} onClick={onClose} />
73	        </DrawerActions>
74	      </DrawerHead>
75	      <Divider />
76	      <DrawerPanelBody id={`${id}-drawer-body`} className="drawer-body scrollable" data-test-id="drawer-body">
77	        <SummaryPanelContent
78	          flows={flows}
79	          metrics={metrics}
80	          type={type}
81	          maxChunkAge={maxChunkAge}
82	          stats={stats}
83	          limit={limit}
84	          range={range}
85	          lastRefresh={lastRefresh}
86	          lastDuration={lastDuration}
87	          warning={warning}
88	          showDNSLatency={showDNSLatency}
89	          showRTTLatency={showRTTLatency}
90	        />
91	      </DrawerPanelBody>
92	    </DrawerPanelContent>
93	  );
94	};
95	
96	export default SummaryPanel;

