 1	import { render, waitFor } from '@testing-library/react';
 2	import * as React from 'react';
 3	
 4	import { defaultNetflowMetrics } from '../../../api/loki';
 5	import { FlowsSample } from '../../../components/__tests-data__/flows';
 6	import { RecordType } from '../../../model/flow-query';
 7	import { SummaryPanelContent } from '../summary-panel-content';
 8	
 9	describe('<SummaryPanel />', () => {
10	  const now = new Date();
11	
12	  const mocks = {
13	    onClose: jest.fn(),
14	    flows: FlowsSample,
15	    metrics: defaultNetflowMetrics,
16	    type: 'flowLog' as RecordType,
17	    stats: {
18	      limitReached: false,
19	      numQueries: 1,
20	      dataSources: ['loki']
21	    },
22	    appStats: undefined,
23	    limit: 5,
24	    range: 300,
25	    lastRefresh: now,
26	    id: 'summary-panel'
27	  };
28	
29	  it('should show cardinality', async () => {
30	    const { container } = render(<SummaryPanelContent {...mocks} />);
31	    await waitFor(() => {
32	      expect(container.querySelector('#addresses')).toBeTruthy();
33	    });
34	
35	    expect(container.querySelector('#addresses')?.textContent).toBe('5 IP(s)');
36	    expect(container.querySelector('#ports')?.textContent).toBe('4 Port(s)');
37	    expect(container.querySelector('#protocols')?.textContent).toBe('1 Protocol(s)');
38	    expect(container.querySelector('#Pod')?.textContent).toBe('2 Pod(s)');
39	    expect(container.querySelector('#Namespace')?.textContent).toBe('1 Namespace(s)');
40	  });
41	});

